import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  webhooks: defineTable({
    payload: v.string(),
    runId: v.string(),
  }),
});

import { query, internalMutation } from "./_generated/server";
import { v } from "convex/values";

export const get_webhook = query({
  args: { runId: v.string() },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("webhooks")
      .filter((q) => q.eq(q.field("runId"), args.runId))
      .collect();
  },
});

export const insert = internalMutation({
  args: { payload: v.string(), runId: v.string() },
  handler: async (ctx, args) => {
    await ctx.db.insert("webhooks", {
      payload: args.payload,
      runId: args.runId,
    });
  },
});

import { httpRouter } from "convex/server";
import { httpAction } from "./_generated/server";
import { internal } from "./_generated/api";

const http = httpRouter();

http.route({
  path: "/webhook",
  method: "POST",
  handler: httpAction(async (ctx, request) => {
    const body = await request.json();
    await ctx.runMutation(internal.webhooks.insert, {
      payload: body.payload,
      runId: body.runId,
    });
    return new Response(null, {
      status: 200,
    });
  }),
});

export default http;

const { ConvexHttpClient } = require("convex/browser");
const client = new ConvexHttpClient(process.env.CONVEX_URL);

async function main() {
  const result = await client.query("webhooks:get_webhook", { runId: "123" });
  console.log(result);
}
main();
